import type { ChartData } from '../types';
import type { AreaChartSeries } from './AreaChart';

interface GetSplitOffsetInput {
  data: ChartData;
  dataKey: string;
}

export function getSplitOffset({ data, dataKey }: GetSplitOffsetInput) {
  const dataMax = Math.max(...data.map((item) => item[dataKey]));
  const dataMin = Math.min(...data.map((item) => item[dataKey]));

  if (dataMax <= 0) {
    return 0;
  }
  if (dataMin >= 0) {
    return 1;
  }

  return dataMax / (dataMax - dataMin);
}

interface GetDefaultSplitOffsetInput {
  data: ChartData;
  series: AreaChartSeries[];
}

export function getDefaultSplitOffset({ data, series }: GetDefaultSplitOffsetInput) {
  if (series.length === 1) {
    const dataKey = series[0].name;
    return getSplitOffset({ data, dataKey });
  }

  return 0.5;
}

export function getPreviousIndex(
  currentIndex: number,
  elements: NodeListOf<HTMLDivElement> | HTMLDivElement[],
  loop: boolean
) {
  for (let i = currentIndex - 1; i >= 0; i -= 1) {
    if (!elements[i].hasAttribute('data-combobox-disabled')) {
      return i;
    }
  }

  if (loop) {
    for (let i = elements.length - 1; i > -1; i -= 1) {
      if (!elements[i].hasAttribute('data-combobox-disabled')) {
        return i;
      }
    }
  }

  return currentIndex;
}

export function getNextIndex(
  currentIndex: number,
  elements: NodeListOf<HTMLDivElement> | HTMLDivElement[],
  loop: boolean
) {
  for (let i = currentIndex + 1; i < elements.length; i += 1) {
    if (!elements[i].hasAttribute('data-combobox-disabled')) {
      return i;
    }
  }

  if (loop) {
    for (let i = 0; i < elements.length; i += 1) {
      if (!elements[i].hasAttribute('data-combobox-disabled')) {
        return i;
      }
    }
  }

  return currentIndex;
}

export function getFirstIndex(elements: NodeListOf<HTMLDivElement> | HTMLDivElement[]) {
  for (let i = 0; i < elements.length; i += 1) {
    if (!elements[i].hasAttribute('data-combobox-disabled')) {
      return i;
    }
  }

  return -1;
}

