import dayjs from 'dayjs';
import { MonthPositionedEventData } from '../../../types';

interface AddEventToDayGroupsInput {
  positionedEvent: MonthPositionedEventData;
  eventStart: dayjs.Dayjs;
  eventEnd: dayjs.Dayjs;
  groupedByDay: { [date: string]: MonthPositionedEventData[] };
  eventsAddedToDay: Set<string>;
  weekIdx: number;
}

export function addEventToDayGroups({
  positionedEvent,
  eventStart,
  eventEnd,
  groupedByDay,
  eventsAddedToDay,
  weekIdx,
}: AddEventToDayGroupsInput): void {
  if (weekIdx === 0 || !eventsAddedToDay.has(positionedEvent.id.toString())) {
    let dayDate = eventStart;
    while (dayDate.isBefore(eventEnd) || dayDate.isSame(eventEnd, 'day')) {
      const dayDateStr = dayDate.format('YYYY-MM-DD 00:00:00');
      if (groupedByDay[dayDateStr]) {
        groupedByDay[dayDateStr].push(positionedEvent);
      }
      dayDate = dayDate.add(1, 'day');
    }
    eventsAddedToDay.add(positionedEvent.id.toString());
  }
}

import dayjs from 'dayjs';
import { DateStringValue, DayOfWeek } from '../../../types';
import { getStartOfWeek } from '../../../utils';

interface GetWeeksInRangeInput {
  rangeStart: dayjs.Dayjs;
  rangeEnd: dayjs.Dayjs;
  firstDayOfWeek: DayOfWeek;
}

interface GetWeeksInRangeOutput {
  weeks: DateStringValue[][];
  groupedByDay: { [date: string]: any[] };
}

export function getWeeksInRange({
  rangeStart,
  rangeEnd,
  firstDayOfWeek,
}: GetWeeksInRangeInput): GetWeeksInRangeOutput {
  const weeks: DateStringValue[][] = [];
  const groupedByDay: { [date: string]: any[] } = {};

  const startOfFirstWeekStr = getStartOfWeek({
    date: rangeStart.format('YYYY-MM-DD'),
    firstDayOfWeek,
  });

  let currentDate = dayjs(startOfFirstWeekStr);

  while (currentDate.isBefore(rangeEnd) || currentDate.isSame(rangeEnd, 'day')) {
    const week: DateStringValue[] = [];
    for (let i = 0; i < 7; i++) {
      const dateStr = currentDate.format('YYYY-MM-DD 00:00:00');
      week.push(dateStr);
      if (!groupedByDay[dateStr]) {
        groupedByDay[dateStr] = [];
      }
      currentDate = currentDate.add(1, 'day');
    }
    weeks.push(week);
  }

  return { weeks, groupedByDay };
}
